const body    = $input.first().json.body || {};
const op      = body.operation || 'check';  // claim | release | check
const emailId = (body.emailId || '').toString().trim();
const agentId = (body.agentId || '').toString().trim();
const agentLabel = (body.agentLabel || agentId || 'Another agent').toString().trim();

const data   = $getWorkflowStaticData('global');
data.claims  = data.claims || {};
const now    = Date.now();
const EXPIRY = 30 * 60 * 1000; // 30 minutes

// Purge stale claims
Object.keys(data.claims).forEach(k => {
  if (now - data.claims[k].claimedAt > EXPIRY) delete data.claims[k];
});

if (op === 'claim' && emailId) {
  data.claims[emailId] = { agentId, agentLabel, claimedAt: now };
}
if (op === 'release' && emailId) {
  // Only the claiming agent can release
  if (!data.claims[emailId] || data.claims[emailId].agentId === agentId)
    delete data.claims[emailId];
}

// Always return current active claims
return [{ json: { success: true, claims: data.claims } }];
